// The status of a batch run:
// * `"PENDING"` - The batch has been created and is waiting to be processed
// * `"PROCESSING"` - The batch is currently being processed
// * `"PROCESSED"` - All runs in the batch have completed successfully
// * `"FAILED"` - The batch failed to process
// * `"CANCELLED"` - The batch was cancelled
type BatchRunStatus string

const (
	BatchRunStatusPending    BatchRunStatus = "PENDING"
	BatchRunStatusProcessing BatchRunStatus = "PROCESSING"
	BatchRunStatusProcessed  BatchRunStatus = "PROCESSED"
	BatchRunStatusFailed     BatchRunStatus = "FAILED"
	BatchRunStatusCancelled  BatchRunStatus = "CANCELLED"
)

func NewBatchRunStatusFromString(s string) (BatchRunStatus, error) {
	switch s {
	case "PENDING":
		return BatchRunStatusPending, nil
	case "PROCESSING":
		return BatchRunStatusProcessing, nil
	case "PROCESSED":
		return BatchRunStatusProcessed, nil
	case "FAILED":
		return BatchRunStatusFailed, nil
	case "CANCELLED":
		return BatchRunStatusCancelled, nil
	}
	var t BatchRunStatus
	return "", fmt.Errorf("%s is not a valid %T", s, t)
}

func (b BatchRunStatus) Ptr() *BatchRunStatus {
	return &b
}

