// The status of the edit run:
// * `"PROCESSING"` - The file is still being processed
// * `"PROCESSED"` - The file was successfully edited
// * `"FAILED"` - The editing failed (see `failureReason` for details)
type EditRunStatus string

const (
	EditRunStatusProcessing EditRunStatus = "PROCESSING"
	EditRunStatusProcessed  EditRunStatus = "PROCESSED"
	EditRunStatusFailed     EditRunStatus = "FAILED"
)

func NewEditRunStatusFromString(s string) (EditRunStatus, error) {
	switch s {
	case "PROCESSING":
		return EditRunStatusProcessing, nil
	case "PROCESSED":
		return EditRunStatusProcessed, nil
	case "FAILED":
		return EditRunStatusFailed, nil
	}
	var t EditRunStatus
	return "", fmt.Errorf("%s is not a valid %T", s, t)
}

func (e EditRunStatus) Ptr() *EditRunStatus {
	return &e
}

