// The type of the file based on the file extension or content type.
type FileType string

const (
	FileTypePdf   FileType = "PDF"
	FileTypeCsv   FileType = "CSV"
	FileTypeImg   FileType = "IMG"
	FileTypeTxt   FileType = "TXT"
	FileTypeDocx  FileType = "DOCX"
	FileTypeExcel FileType = "EXCEL"
	FileTypeXML   FileType = "XML"
	FileTypeHTML  FileType = "HTML"
)

func NewFileTypeFromString(s string) (FileType, error) {
	switch s {
	case "PDF":
		return FileTypePdf, nil
	case "CSV":
		return FileTypeCsv, nil
	case "IMG":
		return FileTypeImg, nil
	case "TXT":
		return FileTypeTxt, nil
	case "DOCX":
		return FileTypeDocx, nil
	case "EXCEL":
		return FileTypeExcel, nil
	case "XML":
		return FileTypeXML, nil
	case "HTML":
		return FileTypeHTML, nil
	}
	var t FileType
	return "", fmt.Errorf("%s is not a valid %T", s, t)
}

func (f FileType) Ptr() *FileType {
	return &f
}

